#include <unistd.h>
#include <sys/wait.h>
#include <sys/types.h>
#include <cstdio>
#include <cerrno>
#include <fcntl.h>

int main() {
    // Create a pipe for communication
    int pipefd[2];
    if (pipe(pipefd) == -1) {
        perror("pipe");
        return 1;
    }

    // Fork a new process
    pid_t pid = fork();
    if (pid == -1) {
        perror("fork");
        return 1;
    } else if (pid == 0) { // Child process
        // Close the write end of the pipe in the child
        close(pipefd[1]);

        // Redirection: Close stdin and stdout, and dup the pipe to them
        close(STDIN_FILENO);
        close(STDOUT_FILENO);
        dup2(pipefd[0], STDIN_FILENO);
        dup2(pipefd[0], STDOUT_FILENO);

        // Execute the command
        execlp("ls", "ls", NULL);
        perror("execlp");
        _exit(1);
    } else { // Parent process
        // Close the read end of the pipe in the parent
        close(pipefd[0]);

        // Write some data to the pipe (optional)
        const char* data = "Hello from parent process";
        ssize_t bytes_written = write(pipefd[1], data, strlen(data));
        if (bytes_written == -1) {
            perror("write");
        }

        // Wait for the child process to finish
        wait(NULL);

        // Close the write end of the pipe in the parent
